// Extract people array and filter out already-contacted IDs
const data = $input.first().json;
const people = data.people || [];

// Format candidates for LLM ranking
const candidates = people.map((p, i) => ({
  index: i,
  id: p.id,
  name: `${p.first_name || ''} ${p.last_name || ''}`.trim(),
  title: p.title || '',
  company: p.organization?.name || '',
  industry: p.organization?.industry || '',
  city: p.organization?.city || '',
  employees: p.organization?.estimated_num_employees || ''
}));

return [{ json: { candidates, total: candidates.length } }];

// Parse the LLM response to extract the array of IDs
const raw = $input.first().json.message?.content || $input.first().json.text || '';
let ids = [];
try {
  // Extract JSON array from the response
  const match = raw.match(/\[.*\]/s);
  if (match) {
    ids = JSON.parse(match[0]);
  }
} catch (e) {
  console.error('Failed to parse LLM response:', raw);
}

return [{ json: { selected_ids: ids.slice(0, 25) } }];

// Extract enriched contacts with emails
const data = $input.first().json;
const matches = data.matches || [];

const contacts = matches
  .filter(p => p && p.email)
  .map(p => ({
    first_name: p.first_name || '',
    last_name: p.last_name || '',
    email: p.email,
    title: p.title || '',
    company_name: p.organization?.name || '',
    company_domain: p.organization?.primary_domain || '',
    company_industry: p.organization?.industry || '',
    company_city: p.organization?.city || '',
    company_state: p.organization?.state || '',
    company_description: p.organization?.short_description || '',
    apollo_id: p.id
  }));

return contacts.map(c => ({ json: c }));

// Strip HTML tags and extract a short text snippet from the homepage
const html = $input.first().json?.body || $input.first().json?.data || '';
const text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 300);

// Merge with contact data from previous node
const contact = $('Extract Contacts with Emails').first().json;

return [{ json: { ...contact, homepage_snippet: text } }];

