// Prepare the final email data for Gmail draft creation
const contact = $('Parse Homepage Snippet').first().json;
const emailBody = $input.first().json.message?.content || $input.first().json.text || '';

const subject = `quick question for ${contact.company_name}`;

return [{ json: {
  to: contact.email,
  subject: subject,
  body: emailBody,
  first_name: contact.first_name,
  last_name: contact.last_name,
  company: contact.company_name,
  apollo_id: contact.apollo_id
} }];
